    public static int Count => Foods.Count;

    public static List<FoodProductDto> Search(string query, int maxResults = 10)
    {
        if (string.IsNullOrWhiteSpace(query)) return [];
        return _index.Value.Search(query, maxResults);
    }

    private static FoodProductDto F(string name, string brand, string ingredients, int cal, decimal protein, decimal carbs, decimal fat, decimal fiber, decimal sugar, decimal sodium) =>
        new()
        {
            Name = name,
            Brand = brand,
            Ingredients = ingredients,
            Calories100g = cal,
            Protein100g = protein,
            Carbs100g = carbs,
            Fat100g = fat,
            Fiber100g = fiber,
            Sugar100g = sugar,
            Sodium100g = sodium,
            DataSource = "USDA",
            FoodKind = FoodKind.Branded,
        };
}
